'use strict';
const http  = require('http');
const https = require('https');

const PORT       = process.env.PORT || 3000;
const GEMINI_KEY = process.env.GEMINI_API_KEY || '';

// ===== IPレート制限 =====
const RL_WIN = 60 * 1000;  // 1分
const RL_MAX = 5;           // 1分あたり5回
const rlMap  = new Map();

function checkRL(ip) {
  const now = Date.now();
  const e   = rlMap.get(ip);
  if (!e || now - e.w > RL_WIN) { rlMap.set(ip, {c:1, w:now}); return true; }
  e.c++;
  return e.c <= RL_MAX;
}
// 古いエントリを5分ごとに削除（メモリリーク防止）
setInterval(() => {
  const now = Date.now();
  for (const [ip, e] of rlMap.entries())
    if (now - e.w > RL_WIN * 5) rlMap.delete(ip);
}, 5 * 60 * 1000);

// ===== HTML =====
const INDEX_HTML = "<!DOCTYPE html>\n<html lang=\"ja\" data-theme=\"dark\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width,initial-scale=1,maximum-scale=1,user-scalable=no\">\n<title>\u3044\u3069\u3070\u305f</title>\n<link href=\"https://fonts.googleapis.com/css2?family=Noto+Sans+JP:wght@400;500;700;900&display=swap\" rel=\"stylesheet\">\n<style>\n/* ===== CSS\u5909\u6570 ===== */\n:root{\n  --bg:#0f0f13;--sf:#1a1a22;--sf2:#22222e;--bd:#2e2e3e;\n  --tx:#f0f0f5;--sub:#8888aa;--like:#ff4488;--acc:#ff6b35;\n  --fn:'Noto Sans JP',sans-serif;\n}\n[data-theme=\"light\"]{\n  --bg:#f5f5f7;--sf:#ffffff;--sf2:#ebebf0;--bd:#d8d8e8;\n  --tx:#111122;--sub:#666688;\n}\n/* ===== \u30ea\u30bb\u30c3\u30c8 ===== */\n*{margin:0;padding:0;box-sizing:border-box;-webkit-tap-highlight-color:transparent;}\nbody{background:var(--bg);color:var(--tx);font-family:var(--fn);min-height:100vh;display:flex;justify-content:center;transition:background .25s,color .25s;}\nbutton,input,textarea{font-family:var(--fn);}\nbutton{cursor:pointer;border:none;background:none;}\na{text-decoration:none;color:inherit;}\n\n/* ===== \u30a2\u30d7\u30ea\u67a0 ===== */\n.app{width:390px;min-height:100vh;background:var(--bg);display:flex;flex-direction:column;position:relative;overflow-x:hidden;}\n@media(max-width:420px){.app{width:100vw;}}\n\n/* ===== \u30b9\u30af\u30ea\u30fc\u30f3\u5207\u66ff ===== */\n.screen{display:none;flex-direction:column;flex:1;}\n.screen.active{display:flex;}\n\n/* ===== \u30ed\u30fc\u30c7\u30a3\u30f3\u30b0\u30aa\u30fc\u30d0\u30fc\u30ec\u30a4 ===== */\n.overlay{position:fixed;inset:0;background:var(--bg);display:flex;flex-direction:column;align-items:center;justify-content:center;z-index:1000;gap:18px;transition:opacity .3s;}\n.overlay.hide{display:none;}\n.ov-logo{font-size:36px;font-weight:900;letter-spacing:-1.5px;}\n.ov-logo em{color:var(--acc);font-style:normal;}\n.ov-sub{font-size:13px;color:var(--sub);}\n.spinner{width:38px;height:38px;border:3px solid var(--bd);border-top-color:var(--acc);border-radius:50%;animation:spin .75s linear infinite;}\n@keyframes spin{to{transform:rotate(360deg);}}\n\n/* ===== \u30bb\u30c3\u30c8\u30a2\u30c3\u30d7\u753b\u9762 ===== */\n#setupScreen{overflow-y:auto;padding-bottom:60px;}\n.s-hero{text-align:center;padding:56px 24px 28px;background:linear-gradient(180deg,var(--sf) 0%,var(--bg) 100%);}\n.s-logo{font-size:46px;font-weight:900;letter-spacing:-2px;margin-bottom:8px;}\n.s-logo em{color:var(--acc);font-style:normal;}\n.s-catchcopy{font-size:14px;color:var(--sub);line-height:1.9;}\n.s-mascot{font-size:68px;margin:14px 0 0;}\n.s-body{padding:24px 20px 0;}\n.s-desc{font-size:13px;color:var(--sub);line-height:1.9;text-align:center;margin-bottom:24px;}\n.s-sec{margin-bottom:22px;}\n.s-lbl{font-size:10.5px;font-weight:700;color:var(--sub);letter-spacing:1.8px;text-transform:uppercase;margin-bottom:8px;}\n.s-inp{width:100%;background:var(--sf);border:1.5px solid var(--bd);border-radius:14px;padding:13px 16px;color:var(--tx);font-size:15px;outline:none;transition:border-color .2s;}\n.s-inp:focus{border-color:var(--acc);}\n.s-inp::placeholder{color:var(--sub);}\n/* \u30a2\u30d0\u30bf\u30fc\u9078\u629e */\n.av-grid{display:flex;flex-wrap:wrap;gap:10px;}\n.av-item{width:52px;height:52px;border-radius:50%;background:var(--sf);border:2px solid var(--bd);display:flex;align-items:center;justify-content:center;font-size:26px;cursor:pointer;transition:all .2s;}\n.av-item.sel{border-color:var(--acc);background:rgba(255,107,53,.15);transform:scale(1.1);}\n/* \u8208\u5473\u30bf\u30b0 */\n.int-grid{display:flex;flex-wrap:wrap;gap:8px;}\n.int-tag{padding:7px 14px;border-radius:20px;border:1.5px solid var(--bd);font-size:12px;font-weight:700;color:var(--sub);cursor:pointer;transition:all .2s;}\n.int-tag.sel{border-color:var(--acc);color:var(--acc);background:rgba(255,107,53,.1);}\n/* \u958b\u59cb\u30dc\u30bf\u30f3 */\n.s-btn{width:100%;padding:15px;border-radius:14px;background:var(--acc);color:#fff;font-size:16px;font-weight:900;margin-top:8px;transition:transform .15s,opacity .15s;}\n.s-btn:hover{transform:translateY(-2px);}\n.s-btn:active{transform:translateY(0);}\n.s-btn:disabled{opacity:.4;transform:none;cursor:not-allowed;}\n\n/* ===== \u30e1\u30a4\u30f3\u753b\u9762 ===== */\n#mainScreen{height:100vh;overflow:hidden;}\n/* \u30d8\u30c3\u30c0\u30fc */\n.hdr{flex-shrink:0;background:color-mix(in srgb,var(--bg) 85%,transparent);backdrop-filter:blur(16px);-webkit-backdrop-filter:blur(16px);border-bottom:1px solid var(--bd);padding:10px 14px 8px;position:sticky;top:0;z-index:100;}\n.hdr-row{display:flex;align-items:center;justify-content:space-between;}\n.hdr-left{display:flex;align-items:center;gap:8px;}\n/* \u30e1\u30cb\u30e5\u30fc\u30dc\u30bf\u30f3 */\n.menu-btn{width:36px;height:36px;border-radius:10px;background:var(--sf);border:1.5px solid var(--bd);display:flex;align-items:center;justify-content:center;font-size:17px;transition:all .2s;flex-shrink:0;}\n.menu-btn:hover{border-color:var(--acc);}\n.logo{font-size:21px;font-weight:900;letter-spacing:-.5px;white-space:nowrap;cursor:pointer;}\n.logo em{color:var(--acc);font-style:normal;}\n.mode-badge{display:inline-block;font-size:11px;font-weight:700;padding:4px 12px;border-radius:20px;background:var(--acc);color:#fff;white-space:nowrap;transition:background .3s;margin-top:6px;}\n.hdr-right{display:flex;align-items:center;gap:5px;}\n.nav-btn{width:34px;height:34px;border-radius:50%;background:var(--sf);border:1.5px solid var(--bd);display:flex;align-items:center;justify-content:center;font-size:15px;transition:all .2s;position:relative;flex-shrink:0;}\n.nav-btn:hover,.nav-btn.on{border-color:var(--acc);background:rgba(255,107,53,.1);}\n.ndot{position:absolute;top:2px;right:2px;width:8px;height:8px;border-radius:50%;background:var(--like);border:2px solid var(--bg);display:none;}\n.ndot.show{display:block;}\n\n/* ===== \u30d1\u30cd\u30eb\u30b7\u30b9\u30c6\u30e0 ===== */\n.panels{flex:1;overflow:hidden;position:relative;}\n.panel{position:absolute;inset:0;overflow-y:auto;padding-bottom:88px;opacity:0;pointer-events:none;transition:opacity .2s;scrollbar-width:thin;scrollbar-color:var(--bd) transparent;}\n.panel.on{opacity:1;pointer-events:auto;}\n.panel-hdr{padding:14px 16px;border-bottom:1px solid var(--bd);display:flex;align-items:center;justify-content:space-between;position:sticky;top:0;background:var(--bg);z-index:10;}\n.panel-ttl{font-size:18px;font-weight:900;}\n.panel-act{color:var(--sub);font-size:12px;}\n\n/* ===== \u6295\u7a3f\u30ab\u30fc\u30c9 ===== */\n.post-card{padding:14px 16px;border-bottom:1px solid var(--bd);transition:background .15s;animation:fadeUp .3s ease;}\n.post-card:hover{background:var(--sf);}\n/* \u30e6\u30fc\u30b6\u30fc\u81ea\u8eab\u306e\u6295\u7a3f\u306f\u5de6border\u4ed8\u304d */\n.post-card.mine{border-left:3px solid var(--acc);background:color-mix(in srgb,var(--acc) 4%,var(--bg));}\n@keyframes fadeUp{from{opacity:0;transform:translateY(8px);}to{opacity:1;transform:translateY(0);}}\n.pc-top{display:flex;gap:11px;align-items:flex-start;}\n/* \u30a2\u30d0\u30bf\u30fc */\n.pc-av{width:44px;height:44px;border-radius:50%;background:var(--sf2);display:flex;align-items:center;justify-content:center;font-size:22px;flex-shrink:0;border:2px solid transparent;}\n.pc-av.mine{border-color:var(--acc);}\n.pc-meta{flex:1;min-width:0;}\n.pc-nr{display:flex;align-items:center;flex-wrap:wrap;gap:5px;margin-bottom:2px;}\n.pc-name{font-size:13px;font-weight:700;}\n.pc-id{font-size:11px;color:var(--sub);}\n/* \u30e2\u30fc\u30c9\u30bf\u30b0 */\n.mtag{font-size:10px;padding:2px 7px;border-radius:10px;font-weight:700;}\n.t-inf{background:rgba(255,107,53,.2);color:#ff6b35;}\n.t-men{background:rgba(91,156,246,.2);color:#5b9cf6;}\n.t-deb{background:rgba(244,63,94,.2);color:#f43f5e;}\n.t-leg{background:rgba(167,139,250,.2);color:#a78bfa;}\n/* \u6295\u7a3f\u672c\u6587 */\n.pc-body{font-size:14px;line-height:1.7;margin:8px 0 10px;word-break:break-word;}\n/* \u30a2\u30af\u30b7\u30e7\u30f3\u30dc\u30bf\u30f3 */\n.pc-acts{display:flex;gap:20px;}\n.act{display:flex;align-items:center;gap:5px;color:var(--sub);font-size:12px;cursor:pointer;transition:color .2s;padding:3px 0;background:none;border:none;}\n.act:hover{color:var(--tx);}\n.act.lkd{color:var(--like);}\n.act-ico{font-size:15px;}\n@keyframes lpop{0%{transform:scale(1);}40%{transform:scale(1.5);}100%{transform:scale(1);}}\n.lpop{animation:lpop .3s ease;}\n\n/* ===== \u30b3\u30e1\u30f3\u30c8\u6b04 ===== */\n.cmt-sec{display:none;background:var(--sf2);border-top:1px solid var(--bd);padding:12px 14px;}\n.cmt-sec.open{display:block;animation:fadeUp .2s ease;}\n.cmt-item{padding:9px 0;border-bottom:1px solid var(--bd);font-size:13px;line-height:1.6;}\n.cmt-item:last-child{border:none;}\n.cmt-who{display:flex;align-items:center;gap:6px;font-size:11px;font-weight:700;color:var(--acc);margin-bottom:4px;}\n.cmt-av{font-size:16px;}\n.cmt-add{display:flex;gap:8px;margin-top:10px;}\n.cmt-inp{flex:1;background:var(--bg);border:1.5px solid var(--bd);border-radius:20px;padding:8px 14px;color:var(--tx);font-size:13px;outline:none;transition:border-color .2s;}\n.cmt-inp:focus{border-color:var(--acc);}\n.cmt-inp::placeholder{color:var(--sub);}\n.cmt-snd{width:32px;height:32px;border-radius:50%;background:var(--acc);color:#fff;font-size:13px;display:flex;align-items:center;justify-content:center;flex-shrink:0;}\n\n/* ===== \u30ed\u30fc\u30c7\u30a3\u30f3\u30b0\u30ab\u30fc\u30c9 ===== */\n.ld-card{padding:14px 16px;border-bottom:1px solid var(--bd);}\n.typing{display:flex;align-items:center;gap:5px;margin-top:6px;}\n.dot{width:7px;height:7px;border-radius:50%;background:var(--sub);animation:bounce 1.2s infinite;}\n.dot:nth-child(2){animation-delay:.2s;}\n.dot:nth-child(3){animation-delay:.4s;}\n@keyframes bounce{0%,60%,100%{transform:translateY(0);opacity:.4;}30%{transform:translateY(-6px);opacity:1;}}\n\n/* ===== \u7a7a\u72b6\u614b ===== */\n.empty{text-align:center;padding:64px 28px;color:var(--sub);}\n.empty-ico{font-size:54px;margin-bottom:16px;}\n.empty-ttl{font-size:17px;font-weight:700;color:var(--tx);margin-bottom:10px;}\n.empty-txt{font-size:13px;line-height:1.8;}\n\n/* ===== \u901a\u77e5\u30d1\u30cd\u30eb ===== */\n.notif-item{padding:14px 16px;border-bottom:1px solid var(--bd);display:flex;gap:12px;align-items:flex-start;animation:fadeUp .3s ease;}\n.notif-item.unread{background:color-mix(in srgb,var(--acc) 4%,var(--bg));}\n.ni-ico{font-size:22px;flex-shrink:0;margin-top:1px;}\n.ni-body{flex:1;}\n.ni-text{font-size:13px;line-height:1.65;margin-bottom:3px;}\n.ni-time{font-size:11px;color:var(--sub);}\n.no-notif{text-align:center;padding:52px 24px;color:var(--sub);font-size:13px;}\n\n/* ===== \u30c8\u30ec\u30f3\u30c9\u30d1\u30cd\u30eb ===== */\n.tr-item{display:flex;align-items:center;padding:14px 16px;border-bottom:1px solid var(--bd);cursor:pointer;transition:background .15s;}\n.tr-item:hover{background:var(--sf);}\n.tr-rank{font-size:17px;font-weight:900;color:var(--sub);width:34px;flex-shrink:0;}\n.tr-rank.top{color:var(--acc);}\n.tr-info{flex:1;}\n.tr-tag{font-size:15px;font-weight:700;margin-bottom:2px;}\n.tr-meta{font-size:11px;color:var(--sub);}\n.tr-cnt{font-size:12px;color:var(--sub);}\n\n/* ===== \u30d7\u30ed\u30d5\u30a3\u30fc\u30eb\u30d1\u30cd\u30eb ===== */\n.pr-hero{padding:24px 20px;border-bottom:1px solid var(--bd);display:flex;gap:16px;align-items:center;}\n.pr-av{width:74px;height:74px;border-radius:50%;background:var(--sf2);display:flex;align-items:center;justify-content:center;font-size:40px;border:3px solid var(--acc);flex-shrink:0;}\n.pr-name{font-size:22px;font-weight:900;}\n.pr-id{font-size:13px;color:var(--sub);margin-bottom:10px;}\n.pr-stats{display:flex;gap:20px;}\n.stat-n{font-size:17px;font-weight:900;color:var(--acc);}\n.stat-l{font-size:11px;color:var(--sub);}\n.pr-sec{padding:16px 20px;border-bottom:1px solid var(--bd);}\n.pr-stl{font-size:10.5px;font-weight:700;color:var(--sub);letter-spacing:1.8px;margin-bottom:10px;}\n.pr-tags{display:flex;flex-wrap:wrap;gap:7px;}\n.pr-tag{padding:5px 13px;border-radius:20px;border:1.5px solid var(--acc);color:var(--acc);font-size:12px;font-weight:700;}\n.pr-acts{padding:16px 20px;display:flex;flex-direction:column;gap:10px;}\n.pr-btn{padding:13px 16px;border-radius:12px;border:1.5px solid var(--bd);background:var(--sf);color:var(--tx);font-size:14px;text-align:left;transition:border-color .2s;}\n.pr-btn:hover{border-color:var(--acc);}\n.pr-btn.danger{color:#f43f5e;border-color:rgba(244,63,94,.3);}\n\n/* ===== \u6295\u7a3f\u5165\u529b\u30d0\u30fc ===== */\n.compose{position:fixed;bottom:0;width:390px;background:color-mix(in srgb,var(--bg) 92%,transparent);backdrop-filter:blur(14px);-webkit-backdrop-filter:blur(14px);border-top:1px solid var(--bd);padding:10px 14px 12px;z-index:200;}\n@media(max-width:420px){.compose{width:100vw;}}\n.cmp-row{display:flex;gap:9px;align-items:flex-end;}\n.cmp-av{width:36px;height:36px;border-radius:50%;background:var(--sf2);display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0;border:2px solid var(--acc);transition:border-color .3s;}\n.cmp-inp{flex:1;background:var(--sf);border:1.5px solid var(--bd);border-radius:22px;padding:10px 16px;color:var(--tx);font-size:14px;resize:none;outline:none;max-height:100px;line-height:1.5;transition:border-color .2s;}\n.cmp-inp:focus{border-color:var(--acc);}\n.cmp-inp::placeholder{color:var(--sub);}\n.snd-btn{width:40px;height:40px;border-radius:50%;background:var(--acc);color:#fff;font-size:16px;display:flex;align-items:center;justify-content:center;flex-shrink:0;transition:all .2s;}\n.snd-btn:hover{transform:scale(1.08);}\n.snd-btn:active{transform:scale(.96);}\n.snd-btn:disabled{opacity:.4;transform:none;cursor:not-allowed;}\n\n/* ===== \u30e2\u30fc\u30c9\u9078\u629e\u30e2\u30fc\u30c0\u30eb ===== */\n.modal-bg{position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:300;display:none;align-items:flex-end;justify-content:center;}\n.modal-bg.open{display:flex;animation:bgFade .2s ease;}\n@keyframes bgFade{from{opacity:0;}to{opacity:1;}}\n.mode-sheet{width:390px;background:var(--sf);border-radius:22px 22px 0 0;padding:18px 20px 44px;animation:slideUp .3s cubic-bezier(.22,.61,.36,1);}\n@keyframes slideUp{from{transform:translateY(100%);}to{transform:translateY(0);}}\n@media(max-width:420px){.mode-sheet{width:100vw;}}\n.sh-bar{width:42px;height:4px;border-radius:2px;background:var(--bd);margin:0 auto 18px;}\n.sh-title{font-size:18px;font-weight:900;margin-bottom:14px;}\n/* \u30e2\u30fc\u30c9\u30ab\u30fc\u30c9 */\n.mode-card{padding:14px 16px;border-radius:14px;border:2px solid var(--bd);margin-bottom:10px;display:flex;align-items:center;gap:14px;cursor:pointer;transition:all .2s;}\n.mode-card:hover{border-color:var(--acc);}\n.mode-card.cur{border-color:var(--acc);background:color-mix(in srgb,var(--acc) 6%,var(--sf));}\n.mc-ico{font-size:30px;flex-shrink:0;}\n.mc-name{font-size:15px;font-weight:700;margin-bottom:3px;}\n.mc-desc{font-size:12px;color:var(--sub);line-height:1.5;}\n\n/* ===== \u30c8\u30fc\u30b9\u30c8 ===== */\n.toast{position:fixed;bottom:96px;left:50%;transform:translateX(-50%) translateY(14px);background:var(--sf2);border:1px solid var(--bd);border-radius:12px;padding:10px 20px;font-size:13px;font-weight:700;opacity:0;transition:all .3s;z-index:500;pointer-events:none;white-space:nowrap;}\n.toast.show{opacity:1;transform:translateX(-50%) translateY(0);}\n\n/* ===== \u3044\u3044\u306d\u30d5\u30ed\u30fc\u30c8\u30a2\u30cb\u30e1 ===== */\n.lf{position:fixed;pointer-events:none;font-size:20px;z-index:999;animation:floatUp 1.2s ease forwards;}\n@keyframes floatUp{0%{opacity:1;transform:translateY(0)scale(1);}100%{opacity:0;transform:translateY(-90px)scale(1.7);}}\n</style>\n</head>\n<body>\n<div class=\"app\" id=\"app\">\n\n<!-- \u30ed\u30fc\u30c7\u30a3\u30f3\u30b0 -->\n<div class=\"overlay\" id=\"overlay\">\n  <div class=\"ov-logo\">\u3044\u3069<em>\u3070\u305f</em></div>\n  <div class=\"spinner\"></div>\n  <div class=\"ov-sub\" id=\"ovTxt\">\u8d77\u52d5\u4e2d\u2026</div>\n</div>\n\n<!-- ========== \u30bb\u30c3\u30c8\u30a2\u30c3\u30d7 ========== -->\n<div class=\"screen\" id=\"setupScreen\">\n  <div class=\"s-hero\">\n    <div class=\"s-logo\">\u3044\u3069<em>\u3070\u305f</em></div>\n    <div class=\"s-catchcopy\">\u79c1\u4ee5\u5916\u5168\u54e1AI\u2049<br>\u3042\u306a\u305f\u3060\u3051\u306e\u7a76\u6975\u306b\u308f\u304c\u307e\u307e\u306aSNS</div>\n    <div class=\"s-mascot\">\ud83e\udea3</div>\n  </div>\n  <div class=\"s-body\">\n    <p class=\"s-desc\">\u300c\u3044\u3069\u3070\u305f\u300d\u3078\u3088\u3046\u3053\u305d\uff01<br>\u521d\u671f\u8a2d\u5b9a\u3092\u3057\u3066\u3001\u3042\u306a\u305f\u3060\u3051\u306e\u4e16\u754c\u3092\u4f5c\u308d\u3046\u3002</p>\n    <div class=\"s-sec\">\n      <div class=\"s-lbl\">\u30e6\u30fc\u30b6\u30fc\u540d</div>\n      <input class=\"s-inp\" id=\"sName\" type=\"text\" placeholder=\"\u4f8b\uff1a\u4e95\u6238\u7aef \u6cf0\u5e0c\" maxlength=\"20\" oninput=\"chkSetup()\">\n    </div>\n    <div class=\"s-sec\">\n      <div class=\"s-lbl\">\u30ed\u30b0\u30a4\u30f3ID</div>\n      <input class=\"s-inp\" id=\"sId\" type=\"text\" placeholder=\"\u4f8b\uff1aidobata_taiki\uff08\u82f1\u6570\u5b57\uff09\" maxlength=\"20\" oninput=\"chkSetup()\">\n    </div>\n    <div class=\"s-sec\">\n      <div class=\"s-lbl\">\u30a2\u30d0\u30bf\u30fc\u3092\u9078\u3076</div>\n      <div class=\"av-grid\" id=\"avGrid\">\n        <div class=\"av-item sel\" data-av=\"\ud83d\ude0a\" onclick=\"selAv(this)\">\ud83d\ude0a</div>\n        <div class=\"av-item\" data-av=\"\ud83d\ude0e\" onclick=\"selAv(this)\">\ud83d\ude0e</div>\n        <div class=\"av-item\" data-av=\"\ud83d\udc36\" onclick=\"selAv(this)\">\ud83d\udc36</div>\n        <div class=\"av-item\" data-av=\"\ud83d\udc31\" onclick=\"selAv(this)\">\ud83d\udc31</div>\n        <div class=\"av-item\" data-av=\"\ud83e\udd8a\" onclick=\"selAv(this)\">\ud83e\udd8a</div>\n        <div class=\"av-item\" data-av=\"\ud83d\udc38\" onclick=\"selAv(this)\">\ud83d\udc38</div>\n        <div class=\"av-item\" data-av=\"\ud83e\udd84\" onclick=\"selAv(this)\">\ud83e\udd84</div>\n        <div class=\"av-item\" data-av=\"\ud83d\udc3c\" onclick=\"selAv(this)\">\ud83d\udc3c</div>\n        <div class=\"av-item\" data-av=\"\ud83e\udd81\" onclick=\"selAv(this)\">\ud83e\udd81</div>\n        <div class=\"av-item\" data-av=\"\ud83d\udc2f\" onclick=\"selAv(this)\">\ud83d\udc2f</div>\n        <div class=\"av-item\" data-av=\"\ud83d\udc3b\" onclick=\"selAv(this)\">\ud83d\udc3b</div>\n        <div class=\"av-item\" data-av=\"\ud83d\udc28\" onclick=\"selAv(this)\">\ud83d\udc28</div>\n      </div>\n    </div>\n    <div class=\"s-sec\">\n      <div class=\"s-lbl\">\u8da3\u5473\u30fb\u8208\u5473\uff08\u8907\u6570\u9078\u629eOK\uff09</div>\n      <div class=\"int-grid\">\n        <div class=\"int-tag\" onclick=\"togInt(this)\">\ud83c\udfb5 \u97f3\u697d</div>\n        <div class=\"int-tag\" onclick=\"togInt(this)\">\ud83c\udfac \u6620\u753b</div>\n        <div class=\"int-tag\" onclick=\"togInt(this)\">\ud83c\udfae \u30b2\u30fc\u30e0</div>\n        <div class=\"int-tag\" onclick=\"togInt(this)\">\ud83c\udf73 \u6599\u7406</div>\n        <div class=\"int-tag\" onclick=\"togInt(this)\">\ud83d\udcbb \u30c6\u30af\u30ce\u30ed\u30b8\u30fc</div>\n        <div class=\"int-tag\" onclick=\"togInt(this)\">\ud83d\udcda \u8aad\u66f8</div>\n        <div class=\"int-tag\" onclick=\"togInt(this)\">\u2708\ufe0f \u65c5\u884c</div>\n        <div class=\"int-tag\" onclick=\"togInt(this)\">\ud83d\udc3e \u52d5\u7269</div>\n        <div class=\"int-tag\" onclick=\"togInt(this)\">\u26bd \u30b9\u30dd\u30fc\u30c4</div>\n        <div class=\"int-tag\" onclick=\"togInt(this)\">\ud83c\udf3f \u30e9\u30a4\u30d5\u30b9\u30bf\u30a4\u30eb</div>\n        <div class=\"int-tag\" onclick=\"togInt(this)\">\ud83c\udfad \u30a2\u30cb\u30e1</div>\n        <div class=\"int-tag\" onclick=\"togInt(this)\">\ud83d\udcb0 \u30d3\u30b8\u30cd\u30b9</div>\n        <div class=\"int-tag\" onclick=\"togInt(this)\">\ud83c\udf1f \u63a8\u3057\u6d3b</div>\n      </div>\n    </div>\n    <button class=\"s-btn\" id=\"setupBtn\" onclick=\"doSetup()\" disabled>\u3044\u3069\u3070\u305f\u3092\u306f\u3058\u3081\u308b \u2192</button>\n  </div>\n</div>\n\n<!-- ========== \u30e1\u30a4\u30f3 ========== -->\n<div class=\"screen\" id=\"mainScreen\" style=\"height:100vh;overflow:hidden;display:none;flex-direction:column;\">\n  <!-- \u30d8\u30c3\u30c0\u30fc -->\n  <div class=\"hdr\">\n    <div class=\"hdr-row\">\n      <div class=\"hdr-left\">\n        <button class=\"menu-btn\" onclick=\"openModal()\" title=\"\u30e1\u30cb\u30e5\u30fc\">\u2630</button>\n        <div class=\"logo\" onclick=\"showPanel('timeline')\">\u3044\u3069<em>\u3070\u305f</em></div>\n      </div>\n      <div class=\"hdr-right\">\n        <button class=\"nav-btn\" id=\"btnTheme\" onclick=\"toggleTheme()\" title=\"\u30c6\u30fc\u30de\u5207\u66ff\">\ud83c\udf19</button>\n        <button class=\"nav-btn\" id=\"btnNotif\" onclick=\"showPanel('notif')\" title=\"\u901a\u77e5\">\ud83d\udd14<div class=\"ndot\" id=\"ndot\"></div></button>\n        <button class=\"nav-btn\" id=\"btnTrends\" onclick=\"showPanel('trends')\" title=\"\u30c8\u30ec\u30f3\u30c9\">\ud83d\udcc8</button>\n        <button class=\"nav-btn\" id=\"btnProfile\" onclick=\"showPanel('profile')\" title=\"\u30d7\u30ed\u30d5\u30a3\u30fc\u30eb\">\ud83d\udc64</button>\n      </div>\n    </div>\n    <div>\n      <div class=\"mode-badge\" id=\"modeBadge\">\ud83d\udd25 \u30a4\u30f3\u30d5\u30eb\u30a8\u30f3\u30b5\u30fc</div>\n    </div>\n  </div>\n\n  <!-- \u30d1\u30cd\u30eb\u7fa4 -->\n  <div class=\"panels\" style=\"flex:1;overflow:hidden;position:relative;\">\n    <!-- \u30bf\u30a4\u30e0\u30e9\u30a4\u30f3 -->\n    <div class=\"panel on\" id=\"pTimeline\"></div>\n\n    <!-- \u901a\u77e5 -->\n    <div class=\"panel\" id=\"pNotif\">\n      <div class=\"panel-hdr\">\n        <span class=\"panel-ttl\">\ud83d\udd14 \u901a\u77e5</span>\n        <button class=\"panel-act\" onclick=\"clearNotifs()\">\u3059\u3079\u3066\u65e2\u8aad</button>\n      </div>\n      <div id=\"notifList\"></div>\n    </div>\n\n    <!-- \u30c8\u30ec\u30f3\u30c9 -->\n    <div class=\"panel\" id=\"pTrends\">\n      <div class=\"panel-hdr\"><span class=\"panel-ttl\">\ud83d\udcc8 \u30c8\u30ec\u30f3\u30c9</span></div>\n      <div id=\"trendsList\"></div>\n    </div>\n\n    <!-- \u30d7\u30ed\u30d5\u30a3\u30fc\u30eb -->\n    <div class=\"panel\" id=\"pProfile\">\n      <div class=\"pr-hero\">\n        <div class=\"pr-av\" id=\"prAv\">\ud83d\ude0a</div>\n        <div>\n          <div class=\"pr-name\" id=\"prName\">\u2014</div>\n          <div class=\"pr-id\" id=\"prId\">@\u2014</div>\n          <div class=\"pr-stats\">\n            <div><div class=\"stat-n\" id=\"stP\">0</div><div class=\"stat-l\">\u6295\u7a3f</div></div>\n            <div><div class=\"stat-n\" id=\"stL\">0</div><div class=\"stat-l\">\u3044\u3044\u306d</div></div>\n            <div><div class=\"stat-n\" id=\"stC\">0</div><div class=\"stat-l\">\u30b3\u30e1\u30f3\u30c8</div></div>\n          </div>\n        </div>\n      </div>\n      <div class=\"pr-sec\"><div class=\"pr-stl\">INTERESTS</div><div class=\"pr-tags\" id=\"prInts\"></div></div>\n      <div class=\"pr-acts\">\n        <button class=\"pr-btn\" onclick=\"editProfile()\">\u270f\ufe0f \u30d7\u30ed\u30d5\u30a3\u30fc\u30eb\u3092\u7de8\u96c6</button>\n        <button class=\"pr-btn danger\" onclick=\"clearAll()\">\ud83d\uddd1\ufe0f \u30c7\u30fc\u30bf\u3092\u3059\u3079\u3066\u524a\u9664</button>\n      </div>\n    </div>\n  </div>\n\n  <!-- \u6295\u7a3f\u5165\u529b\u30d0\u30fc -->\n  <div class=\"compose\" id=\"compose\">\n    <div class=\"cmp-row\">\n      <div class=\"cmp-av\" id=\"cmpAv\">\ud83d\ude0a</div>\n      <textarea class=\"cmp-inp\" id=\"postInput\" placeholder=\"\u3044\u307e\u3069\u3093\u306a\u6c17\u6301\u3061\uff1f\" rows=\"1\"\n        oninput=\"autoResize(this)\" onkeydown=\"handleKey(event)\"></textarea>\n      <button class=\"snd-btn\" id=\"sendBtn\" onclick=\"submitPost()\" disabled>\u27a4</button>\n    </div>\n  </div>\n</div>\n\n</div><!-- /app -->\n\n<!-- \u30e2\u30fc\u30c9\u9078\u629e\u30e2\u30fc\u30c0\u30eb -->\n<div class=\"modal-bg\" id=\"modeModal\" onclick=\"bgClose(event)\">\n  <div class=\"mode-sheet\" onclick=\"event.stopPropagation()\">\n    <div class=\"sh-bar\"></div>\n    <div class=\"sh-title\">\u30e2\u30fc\u30c9\u3092\u9078\u629e</div>\n    <div class=\"mode-card cur\" data-mode=\"influencer\" onclick=\"selectMode('influencer')\">\n      <div class=\"mc-ico\">\ud83d\udd25</div>\n      <div><div class=\"mc-name\">\u30a4\u30f3\u30d5\u30eb\u30a8\u30f3\u30b5\u30fc\u30e2\u30fc\u30c9</div><div class=\"mc-desc\">\u3042\u306a\u305f\u306e\u6295\u7a3f\u306b\u307f\u3093\u306a\u304c\u71b1\u72c2\uff01\u30d0\u30ba\u308a\u4f53\u9a13\u3092\u3069\u3046\u305e</div></div>\n    </div>\n    <div class=\"mode-card\" data-mode=\"mental\" onclick=\"selectMode('mental')\">\n      <div class=\"mc-ico\">\ud83d\udc99</div>\n      <div><div class=\"mc-name\">\u30e1\u30f3\u30bf\u30eb\u30b1\u30a2\u30e2\u30fc\u30c9</div><div class=\"mc-desc\">\u8ab0\u306b\u3082\u8a00\u3048\u306a\u3044\u60a9\u307f\u3092\u305d\u3063\u3068\u8a71\u3057\u3066\u307f\u3066</div></div>\n    </div>\n    <div class=\"mode-card\" data-mode=\"debate\" onclick=\"selectMode('debate')\">\n      <div class=\"mc-ico\">\u26a1</div>\n      <div><div class=\"mc-name\">\u30c7\u30a3\u30d9\u30fc\u30c8\u30e2\u30fc\u30c9</div><div class=\"mc-desc\">\u610f\u898b\u3092\u3076\u3064\u3051\u3088\u3046\u3002\u8b70\u8ad6\u3067\u601d\u8003\u3092\u6df1\u3081\u308b</div></div>\n    </div>\n    <div class=\"mode-card\" data-mode=\"legend\" onclick=\"selectMode('legend')\">\n      <div class=\"mc-ico\">\ud83d\udc51</div>\n      <div><div class=\"mc-name\">\u30ec\u30b8\u30a7\u30f3\u30c9\u30c8\u30fc\u30af\u30e2\u30fc\u30c9</div><div class=\"mc-desc\">\u6b74\u53f2\u4e0a\u306e\u5049\u4eba\u305f\u3061\u3068\u8a9e\u308a\u5408\u304a\u3046</div></div>\n    </div>\n  </div>\n</div>\n\n<div class=\"toast\" id=\"toast\"></div>\n\n<script>\n'use strict';\n// ===================================================\n//  \u5b9a\u6570\u30fb\u8a2d\u5b9a\n// ===================================================\nconst STORE_KEY = 'idobata_v6';\n\n// \u30e2\u30fc\u30c9\u8a2d\u5b9a\nconst MC = {\n  influencer:{ label:'\u30a4\u30f3\u30d5\u30eb\u30a8\u30f3\u30b5\u30fc', badge:'\ud83d\udd25 \u30a4\u30f3\u30d5\u30eb\u30a8\u30f3\u30b5\u30fc', acc:'#ff6b35', tc:'t-inf', ph:'\u30d0\u30ba\u3089\u305b\u305f\u3044\u3053\u3068\u3092\u3064\u3076\u3084\u3044\u3066\uff01' },\n  mental:    { label:'\u30e1\u30f3\u30bf\u30eb\u30b1\u30a2',     badge:'\ud83d\udc99 \u30e1\u30f3\u30bf\u30eb\u30b1\u30a2',     acc:'#5b9cf6', tc:'t-men', ph:'\u60a9\u307f\u3092\u5171\u6709\u2026' },\n  debate:    { label:'\u30c7\u30a3\u30d9\u30fc\u30c8',       badge:'\u26a1 \u30c7\u30a3\u30d9\u30fc\u30c8',       acc:'#f43f5e', tc:'t-deb', ph:'\u610f\u898b\u3092\u3076\u3064\u3051\u3088\u3046\uff01' },\n  legend:    { label:'\u30ec\u30b8\u30a7\u30f3\u30c9\u30c8\u30fc\u30af', badge:'\ud83d\udc51 \u30ec\u30b8\u30a7\u30f3\u30c9\u30c8\u30fc\u30af', acc:'#a78bfa', tc:'t-leg', ph:'\u6b74\u53f2\u4e0a\u306e\u4eba\u3068\u8a71\u305d\u3046\u2026' },\n};\n\n// AI\u30ad\u30e3\u30e9\u540d\u30d7\u30fc\u30eb\uff08\u3044\u3044\u306d\u901a\u77e5\u306b\u4f7f\u7528\uff09\nconst AI_NAMES = ['\u8c61\u306e\u308a\u9020','\u7b4b\u8089\u5bff\u559c\u7537','\u30c1\u30ef\u30ef\u306b\u306a\u308a\u305f\u3044\u72ac','\u30d1\u30bd\u30b3\u30f3\u3081\u304c\u306d','\u3054\u98ef\u529b\u58eb',\n  '\u3089\u304f\u3060\u5c0f\u50e7','\u30bf\u30e9\u30d0\u30ac\u30cb','\u30d6\u30c3\u30c0','\u30bd\u30af\u30e9\u30c6\u30b9','\u5948\u826f\u3067\u9e7f\u3084\u3063\u3066\u307e\u3059',\n  '\u30e1\u30ed\u30f3\u30bd\u30fc\u30c0','\u30ed\u30dc\u30c3\u30c8\u30ea\u30ad\u30b7','\u7a7a\u304d\u5730\u306e\u54f2\u5b66\u8005','\u6df1\u591c\u306e\u4e3b\u5a66','\u5bdd\u8d77\u304d\u306e\u5927\u5b66\u751f'];\n\n// ===================================================\n//  \u30a2\u30d7\u30ea\u72b6\u614b\n// ===================================================\nlet user     = { name:'', id:'', avatar:'\ud83d\ude0a', interests:[], theme:'dark' };\n// \u30e2\u30fc\u30c9\u3054\u3068\u306b\u72ec\u7acb\u3057\u305f\u30bf\u30a4\u30e0\u30e9\u30a4\u30f3\nlet mPosts   = { influencer:[], mental:[], debate:[], legend:[] };\nlet trends   = [];\nlet notifs   = [];\nlet curMode  = 'influencer';\nlet curPanel = 'timeline';\nlet busy     = false;\nlet pidCtr   = 0;\nlet unread   = 0;\nlet ltimers  = [];\nlet selAv_   = '\ud83d\ude0a';\n\n// ===================================================\n//  \u30bb\u30c3\u30c8\u30a2\u30c3\u30d7\n// ===================================================\nfunction selAv(el) {\n  document.querySelectorAll('.av-item').forEach(e => e.classList.remove('sel'));\n  el.classList.add('sel');\n  selAv_ = el.dataset.av;\n}\nfunction togInt(el) { el.classList.toggle('sel'); }\nfunction chkSetup() {\n  const n = document.getElementById('sName').value.trim();\n  const i = document.getElementById('sId').value.trim();\n  document.getElementById('setupBtn').disabled = !(n && i);\n}\n\nasync function doSetup() {\n  const name = document.getElementById('sName').value.trim();\n  const id   = '@' + document.getElementById('sId').value.trim().replace(/^@/, '');\n  const interests = [...document.querySelectorAll('.int-tag.sel')].map(e => e.textContent.trim());\n  user = { name, id, avatar: selAv_, interests, theme: user.theme || 'dark' };\n  saveData();\n  await toMain(true);\n}\n\n// ===================================================\n//  \u30e1\u30a4\u30f3\u753b\u9762\u3078\u79fb\u884c\n// ===================================================\nasync function toMain(isNew = false) {\n  document.getElementById('setupScreen').classList.remove('active');\n  const ms = document.getElementById('mainScreen');\n  ms.classList.add('active');\n  ms.style.display = 'flex';\n  applyMode(curMode);\n  applyTheme(user.theme || 'dark');\n  updCmpAv();\n  renderTL();\n  renderTrends();\n  updProfile();\n  renderNotifs();\n  if (isNew) {\n    reqNotifPerm();\n    await loadInitTL();\n  }\n  hideLd();\n}\n\n// ===================================================\n//  \u30c6\u30fc\u30de\u5207\u66ff\n// ===================================================\nfunction applyTheme(t) {\n  document.documentElement.setAttribute('data-theme', t);\n  document.getElementById('btnTheme').textContent = t === 'dark' ? '\ud83c\udf19' : '\u2600\ufe0f';\n}\nfunction toggleTheme() {\n  user.theme = user.theme === 'dark' ? 'light' : 'dark';\n  applyTheme(user.theme);\n  saveData();\n}\n\n// ===================================================\n//  \u30e2\u30fc\u30c9\u30e2\u30fc\u30c0\u30eb\n// ===================================================\nfunction openModal() {\n  document.getElementById('modeModal').classList.add('open');\n  document.querySelectorAll('.mode-card').forEach(c =>\n    c.classList.toggle('cur', c.dataset.mode === curMode));\n}\nfunction bgClose(e) {\n  if (e.target === document.getElementById('modeModal'))\n    document.getElementById('modeModal').classList.remove('open');\n}\nfunction selectMode(mode) {\n  document.getElementById('modeModal').classList.remove('open');\n  if (mode === curMode) return;\n  curMode = mode;\n  applyMode(mode);\n  showPanel('timeline');\n  saveData();\n}\nfunction applyMode(mode) {\n  const c = MC[mode];\n  document.documentElement.style.setProperty('--acc', c.acc);\n  document.getElementById('modeBadge').textContent = c.badge;\n  const inp = document.getElementById('postInput');\n  if (inp) inp.placeholder = c.ph;\n  updCmpAv();\n  renderTL(); // \u30e2\u30fc\u30c9\u5207\u66ff\u6642\u306f\u305d\u306e\u30e2\u30fc\u30c9\u306eTL\u3092\u8868\u793a\n}\n\n// ===================================================\n//  \u30d1\u30cd\u30eb\u5207\u66ff\n// ===================================================\nfunction showPanel(name) {\n  curPanel = name;\n  document.querySelectorAll('.panel').forEach(p => p.classList.remove('on'));\n  document.getElementById('compose').style.display = name === 'timeline' ? '' : 'none';\n  ['btnNotif','btnTrends','btnProfile'].forEach(id => document.getElementById(id).classList.remove('on'));\n  const map = { timeline:'pTimeline', notif:'pNotif', trends:'pTrends', profile:'pProfile' };\n  document.getElementById(map[name] || 'pTimeline').classList.add('on');\n  if (name === 'notif')   { document.getElementById('btnNotif').classList.add('on'); markRead(); renderNotifs(); }\n  if (name === 'trends')  { document.getElementById('btnTrends').classList.add('on'); renderTrends(); }\n  if (name === 'profile') { document.getElementById('btnProfile').classList.add('on'); updProfile(); }\n}\n\n// ===================================================\n//  \u521d\u56de\u30bf\u30a4\u30e0\u30e9\u30a4\u30f3\uff08\u8d77\u52d5\u6642\u306e\u307fAPI\u547c\u3073\u51fa\u3057\uff09\n// ===================================================\nasync function loadInitTL() {\n  if (!user.interests.length) return;\n  showLd('\u3042\u306a\u305f\u306e\u8da3\u5473\u306b\u5408\u308f\u305b\u305f\u30bf\u30a4\u30e0\u30e9\u30a4\u30f3\u3092\u6e96\u5099\u4e2d\u2026');\n  try {\n    const r = await fetch('/api/timeline', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({ interests: user.interests, mode: curMode })\n    });\n    if (!r.ok) throw new Error('HTTP ' + r.status);\n    const { posts = [] } = await r.json();\n    posts.forEach(p => mPosts[curMode].push(mkAI(p, curMode)));\n    renderTL();\n    saveData();\n    startLikeSim();\n  } catch(e) {\n    console.warn('initTL:', e.message);\n  }\n  hideLd();\n}\n\n// ===================================================\n//  \u6295\u7a3f\u9001\u4fe1\n// ===================================================\nasync function submitPost() {\n  const ta = document.getElementById('postInput');\n  const text = ta.value.trim();\n  if (!text || busy) return;\n  busy = true;\n  document.getElementById('sendBtn').disabled = true;\n  ta.value = ''; ta.style.height = 'auto';\n  showPanel('timeline');\n\n  // \u30e6\u30fc\u30b6\u30fc\u6295\u7a3f\u3092\u30bf\u30a4\u30e0\u30e9\u30a4\u30f3\u306b\u8ffd\u52a0\n  const pid = ++pidCtr;\n  const up = {\n    id: pid, type: 'user', text,\n    name: user.name, uid: user.id, avatar: user.avatar,\n    mode: curMode, likes: 0, liked: false, comments: [], ts: Date.now()\n  };\n  mPosts[curMode].push(up);\n  renderTL();\n\n  // \u30ed\u30fc\u30c7\u30a3\u30f3\u30b0\u30ab\u30fc\u30c9\u30923\u679a\u8868\u793a\n  const lids = ['a','b','c'].map(x => `ld-${pid}-${x}`);\n  lids.forEach(id => addLdCard(id));\n  scrollBot();\n\n  try {\n    const r = await fetch('/api/post', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({ text, mode: curMode, interests: user.interests })\n    });\n    if (!r.ok) {\n      if (r.status === 429) throw new Error('RATE_LIMIT');\n      const d = await r.json().catch(() => ({}));\n      if (d.error === 'QUOTA_EXCEEDED') throw new Error('QUOTA_EXCEEDED');\n      throw new Error('HTTP_' + r.status);\n    }\n    const { replies = [], timelinePosts = [] } = await r.json();\n\n    // \u30ed\u30fc\u30c7\u30a3\u30f3\u30b0\u524a\u9664\n    lids.forEach(id => document.getElementById(id)?.remove());\n\n    // replies \u2192 \u30b3\u30e1\u30f3\u30c8\u6b04\u306b\u683c\u7d0d\uff08\u30bf\u30a4\u30e0\u30e9\u30a4\u30f3\u306b\u306f\u51fa\u3055\u306a\u3044\uff09\n    if (replies.length) {\n      up.comments.push(...replies.map(r => ({\n        a: r.name, t: r.comment, av: r.avatar || '\ud83e\udd16', lk: r.likes || 0\n      })));\n      const cc = document.getElementById('cc-' + pid);\n      if (cc) cc.textContent = up.comments.length;\n    }\n\n    // timelinePosts \u2192 \u30bf\u30a4\u30e0\u30e9\u30a4\u30f3\u306b\u6d41\u308c\u308bAI\u306e\u3064\u3076\u3084\u304d\n    timelinePosts.forEach((p, i) => {\n      const ap = mkAI(p, curMode);\n      mPosts[curMode].push(ap);\n      setTimeout(() => { appendCard(ap); scrollBot(); }, i * 200 + 100);\n    });\n\n    addHashtags(text);\n    scheduleAutoLikes(pid);\n    setTimeout(() => { saveData(); renderTrends(); }, 1500);\n\n  } catch(err) {\n    lids.forEach(id => document.getElementById(id)?.remove());\n    const fb = getFallback(curMode);\n    if (err.message === 'RATE_LIMIT') {\n      toast('\u26a0\ufe0f \u5c11\u3057\u5f85\u3063\u3066\u304b\u3089\u6295\u7a3f\u3057\u3066\u304f\u3060\u3055\u3044');\n    } else if (err.message === 'QUOTA_EXCEEDED') {\n      toast('\ud83d\ude14 AI\u306e\u5229\u7528\u4e0a\u9650\u306b\u9054\u3057\u307e\u3057\u305f\u3002\u3057\u3070\u3089\u304f\u5f8c\u3067');\n      up.comments.push(...fb.map(r => ({ a:r.name, t:r.comment, av:r.avatar||'\ud83e\udd16', lk:r.likes||0 })));\n      document.getElementById('cc-'+pid)?.textContent !== undefined &&\n        (document.getElementById('cc-'+pid).textContent = up.comments.length);\n    } else {\n      console.warn('API error:', err.message);\n      up.comments.push(...fb.map(r => ({ a:r.name, t:r.comment, av:r.avatar||'\ud83e\udd16', lk:r.likes||0 })));\n      const cc = document.getElementById('cc-'+pid);\n      if (cc) cc.textContent = up.comments.length;\n    }\n    scheduleAutoLikes(pid);\n    saveData();\n  }\n\n  busy = false;\n  document.getElementById('sendBtn').disabled = document.getElementById('postInput').value.trim() === '';\n  saveData();\n}\n\n// ===================================================\n//  \u30d8\u30eb\u30d1\u30fc: AI\u6295\u7a3f\u30aa\u30d6\u30b8\u30a7\u30af\u30c8\u751f\u6210\n// ===================================================\nfunction mkAI(p, mode) {\n  return {\n    id: ++pidCtr, type: 'ai',\n    text: p.comment, name: p.name, uid: p.id || '',\n    avatar: p.avatar || '\ud83c\udf1f', mode,\n    likes: p.likes || Math.floor(Math.random() * 5000) + 10,\n    liked: false, comments: [], ts: Date.now()\n  };\n}\n\n// ===================================================\n//  \u30bf\u30a4\u30e0\u30e9\u30a4\u30f3\u63cf\u753b\n// ===================================================\nfunction renderTL() {\n  const panel = document.getElementById('pTimeline');\n  const posts = mPosts[curMode] || [];\n  if (!posts.length) {\n    panel.innerHTML = '<div class=\"empty\"><div class=\"empty-ico\">\ud83e\udea3</div><div class=\"empty-ttl\">\u4e95\u6238\u7aef\u4f1a\u8b70\u3078\u3088\u3046\u3053\u305d\uff01</div><div class=\"empty-txt\">\u4f55\u3067\u3082\u3064\u3076\u3084\u3044\u3066\u307f\u3088\u3046\u3002<br>AI\u305f\u3061\u304c\u5fc5\u305a\u53cd\u5fdc\u3057\u3066\u304f\u308c\u308b\u3088\u2728</div></div>';\n    return;\n  }\n  panel.innerHTML = '';\n  posts.forEach(p => appendCard(p, false));\n}\n\nfunction appendCard(p, anim = true) {\n  const panel = document.getElementById('pTimeline');\n  panel.querySelector('.empty')?.remove();\n  const d = document.createElement('div');\n  d.className = 'post-card' + (p.type === 'user' ? ' mine' : '');\n  d.id = 'pc-' + p.id;\n  if (!anim) d.style.animationDuration = '0s';\n  const c = MC[p.mode] || MC.influencer;\n  const tag = p.type === 'ai' ? `<span class=\"mtag ${c.tc}\">${c.badge}</span>` : '';\n  const li  = p.liked ? '\u2764\ufe0f' : '\ud83e\udd0d';\n  d.innerHTML = `\n    <div class=\"pc-top\">\n      <div class=\"pc-av${p.type==='user'?' mine':''}\">${p.avatar}</div>\n      <div class=\"pc-meta\">\n        <div class=\"pc-nr\">\n          <span class=\"pc-name\"${p.type==='user'?' style=\"color:var(--acc)\"':''}>${esc(p.name)}</span>\n          <span class=\"pc-id\">${esc(p.uid)}</span>${tag}\n        </div>\n      </div>\n    </div>\n    <div class=\"pc-body\">${esc(p.text)}</div>\n    <div class=\"pc-acts\">\n      <button class=\"act\" onclick=\"togCmt(${p.id})\">\n        <span class=\"act-ico\">\ud83d\udcac</span><span id=\"cc-${p.id}\">${p.comments?.length||0}</span>\n      </button>\n      <button class=\"act${p.liked?' lkd':''}\" id=\"lb-${p.id}\" onclick=\"togLike(${p.id})\">\n        <span id=\"li-${p.id}\">${li}</span><span id=\"lc-${p.id}\">${fmt(p.likes)}</span>\n      </button>\n    </div>\n    <div class=\"cmt-sec\" id=\"cw-${p.id}\">\n      <div id=\"cl-${p.id}\">${renderCmts(p.comments)}</div>\n      <div class=\"cmt-add\">\n        <input class=\"cmt-inp\" id=\"ci-${p.id}\" placeholder=\"\u30b3\u30e1\u30f3\u30c8\u3092\u5165\u529b\u2026\" onkeydown=\"cmtKey(event,${p.id})\">\n        <button class=\"cmt-snd\" onclick=\"addCmt(${p.id})\">\u27a4</button>\n      </div>\n    </div>`;\n  panel.appendChild(d);\n}\n\nfunction addLdCard(lid) {\n  const panel = document.getElementById('pTimeline');\n  panel.querySelector('.empty')?.remove();\n  const d = document.createElement('div');\n  d.className = 'ld-card'; d.id = lid;\n  d.innerHTML = '<div class=\"pc-top\"><div class=\"pc-av\">\u23f3</div><div class=\"pc-meta\"><div class=\"pc-nr\"><span class=\"pc-name\" style=\"color:var(--sub)\">\u8003\u3048\u4e2d\u2026</span></div></div></div><div class=\"typing\"><div class=\"dot\"></div><div class=\"dot\"></div><div class=\"dot\"></div></div>';\n  panel.appendChild(d);\n}\n\nfunction renderCmts(cmts) {\n  if (!cmts?.length) return '';\n  return cmts.map(c => `\n    <div class=\"cmt-item\">\n      <div class=\"cmt-who\"><span class=\"cmt-av\">${c.av||'\ud83e\udd16'}</span>${esc(c.a)}</div>\n      <div>${esc(c.t)}</div>\n    </div>`).join('');\n}\n\n// ===================================================\n//  \u30a4\u30f3\u30bf\u30e9\u30af\u30b7\u30e7\u30f3\n// ===================================================\nfunction togLike(pid) {\n  const p = findPost(pid); if (!p) return;\n  p.liked = !p.liked; p.likes += p.liked ? 1 : -1;\n  const btn = document.getElementById('lb-'+pid);\n  if (btn) {\n    btn.className = 'act' + (p.liked ? ' lkd' : '');\n    btn.innerHTML = `<span id=\"li-${pid}\">${p.liked?'\u2764\ufe0f':'\ud83e\udd0d'}</span><span id=\"lc-${pid}\">${fmt(p.likes)}</span>`;\n    if (p.liked) { btn.classList.add('lpop'); setTimeout(() => btn.classList.remove('lpop'), 400); }\n  }\n  if (p.liked) showLikeFloat();\n  saveData();\n}\nfunction findPost(pid) {\n  for (const arr of Object.values(mPosts)) {\n    const p = arr.find(x => x.id === pid);\n    if (p) return p;\n  }\n  return null;\n}\nfunction togCmt(pid) { document.getElementById('cw-'+pid)?.classList.toggle('open'); }\nfunction cmtKey(e, pid) { if (e.key === 'Enter') addCmt(pid); }\nfunction addCmt(pid) {\n  const inp = document.getElementById('ci-'+pid); if (!inp) return;\n  const t = inp.value.trim(); if (!t) return;\n  const p = findPost(pid); if (!p) return;\n  p.comments.push({ a: user.name || '\u3042\u306a\u305f', t, av: user.avatar });\n  inp.value = '';\n  const cl = document.getElementById('cl-'+pid);\n  if (cl) cl.innerHTML = renderCmts(p.comments);\n  const cc = document.getElementById('cc-'+pid);\n  if (cc) cc.textContent = p.comments.length;\n  saveData(); toast('\ud83d\udcac \u30b3\u30e1\u30f3\u30c8\u3057\u307e\u3057\u305f\uff01');\n}\n\n// ===================================================\n//  \u81ea\u52d5\u3044\u3044\u306d\u30b7\u30df\u30e5\u30ec\u30fc\u30b7\u30e7\u30f3\n// ===================================================\nfunction scheduleAutoLikes(pid) {\n  [\n    {d:20000, mn:2, mx:15},\n    {d:70000, mn:8, mx:60},\n    {d:200000, mn:25, mx:180},\n    {d:450000, mn:60, mx:450},\n    {d:800000, mn:120, mx:1000},\n  ].forEach(({d, mn, mx}) => {\n    ltimers.push(setTimeout(() =>\n      autoLike(pid, Math.floor(Math.random() * (mx - mn) + mn)),\n      d + Math.random() * 15000));\n  });\n}\n\nfunction autoLike(pid, cnt) {\n  const p = findPost(pid); if (!p) return;\n  p.likes += cnt;\n  const lc = document.getElementById('lc-'+pid);\n  if (lc) lc.textContent = fmt(p.likes);\n  const lb = document.getElementById('lb-'+pid);\n  if (lb) { lb.classList.add('lpop'); setTimeout(() => lb.classList.remove('lpop'), 400); }\n  const who = AI_NAMES[Math.floor(Math.random() * AI_NAMES.length)];\n  const msg = cnt >= 50\n    ? `\ud83d\udd25 ${who}\u3055\u3093\u307b\u304b${fmt(cnt)}\u4eba\u304c\u3042\u306a\u305f\u306e\u6295\u7a3f\u3092\u3044\u3044\u306d\uff01`\n    : `\u2764\ufe0f ${who}\u3055\u3093\u304c\u3044\u3044\u306d\u3057\u307e\u3057\u305f`;\n  addNotif(msg, p.text);\n  pushNotif('\u3044\u3069\u3070\u305f\u901a\u77e5', msg);\n  showLikeFloat();\n  saveData();\n}\n\nfunction startLikeSim() {\n  ltimers.push(setInterval(() => {\n    const all = Object.values(mPosts).flat().filter(p => p.type === 'user');\n    if (!all.length) return;\n    autoLike(all[Math.floor(Math.random() * all.length)].id,\n             Math.floor(Math.random() * 30) + 1);\n  }, 90000 + Math.random() * 90000));\n}\n\nfunction showLikeFloat() {\n  const el = document.createElement('div');\n  el.className = 'lf'; el.textContent = '\u2764\ufe0f';\n  el.style.left = (80 + Math.random() * 200) + 'px';\n  el.style.bottom = '100px';\n  document.getElementById('app').appendChild(el);\n  setTimeout(() => el.remove(), 1300);\n}\n\n// ===================================================\n//  \u901a\u77e5\n// ===================================================\nfunction reqNotifPerm() {\n  if ('Notification' in window && Notification.permission === 'default')\n    Notification.requestPermission();\n}\nfunction pushNotif(title, body) {\n  if ('Notification' in window && Notification.permission === 'granted')\n    try { new Notification(title, {body}); } catch(e) {}\n}\nfunction addNotif(text, postText = '') {\n  notifs.unshift({\n    text,\n    pt: postText.slice(0, 30) + (postText.length > 30 ? '\u2026' : ''),\n    ts: Date.now(), read: false\n  });\n  unread++;\n  document.getElementById('ndot').classList.add('show');\n  if (curPanel === 'notif') renderNotifs();\n  saveData();\n}\nfunction renderNotifs() {\n  const list = document.getElementById('notifList');\n  if (!notifs.length) { list.innerHTML = '<div class=\"no-notif\">\u307e\u3060\u901a\u77e5\u306f\u3042\u308a\u307e\u305b\u3093</div>'; return; }\n  list.innerHTML = notifs.slice(0, 30).map(n => `\n    <div class=\"notif-item${n.read ? '' : ' unread'}\">\n      <div class=\"ni-ico\">${n.text.startsWith('\ud83d\udd25') ? '\ud83d\udd25' : '\u2764\ufe0f'}</div>\n      <div class=\"ni-body\">\n        <div class=\"ni-text\">${esc(n.text)}</div>\n        <div class=\"ni-time\">${n.pt ? `\u300c${esc(n.pt)}\u300d\u3078\u306e\u53cd\u5fdc \u00b7 ` : ''}${timeAgo(n.ts)}</div>\n      </div>\n    </div>`).join('');\n}\nfunction markRead() {\n  notifs.forEach(n => n.read = true); unread = 0;\n  document.getElementById('ndot').classList.remove('show');\n  saveData();\n}\nfunction clearNotifs() {\n  notifs = []; unread = 0;\n  document.getElementById('ndot').classList.remove('show');\n  renderNotifs(); saveData();\n}\n\n// ===================================================\n//  \u30c8\u30ec\u30f3\u30c9\n// ===================================================\nconst DEF_TRENDS = [\n  {tag:'#\u3044\u3069\u3070\u305f',cnt:9821,mode:'influencer'},{tag:'#\u5375\u304b\u3051\u3054\u98ef',cnt:4502,mode:'influencer'},\n  {tag:'#\u604b\u30d0\u30ca',cnt:3310,mode:'mental'},{tag:'#TKG',cnt:2889,mode:'influencer'},\n  {tag:'#\u30d6\u30c3\u30c0',cnt:1740,mode:'legend'},{tag:'#\u5bbf\u984c',cnt:933,mode:'debate'},\n  {tag:'#\u97f3\u697d',cnt:788,mode:'influencer'},{tag:'#\u3054\u306f\u3093',cnt:621,mode:'influencer'},\n  {tag:'#\u521d\u30c7\u30fc\u30c8',cnt:489,mode:'mental'},{tag:'#\u6599\u7406',cnt:302,mode:'influencer'},\n];\nfunction addHashtags(text) {\n  (text.match(/#[\\w\u3000-\u9fff\uf900-\ufaff]+/g) || []).forEach(tag => {\n    const ex = trends.find(t => t.tag === tag);\n    if (ex) ex.cnt++; else trends.push({tag, cnt:1, mode:curMode});\n  });\n}\nfunction renderTrends() {\n  DEF_TRENDS.forEach(d => { if (!trends.find(t => t.tag === d.tag)) trends.push({...d}); });\n  (user.interests || []).forEach(int => {\n    const tag = '#' + int.replace(/^.+\\s/, '');\n    if (!trends.find(t => t.tag === tag)) trends.push({tag, cnt: Math.floor(Math.random()*200)+20, mode:'influencer'});\n  });\n  const ml = {influencer:'\u30a4\u30f3\u30d5\u30eb\u30a8\u30f3\u30b5\u30fc',mental:'\u30e1\u30f3\u30bf\u30eb\u30b1\u30a2',debate:'\u30c7\u30a3\u30d9\u30fc\u30c8',legend:'\u30ec\u30b8\u30a7\u30f3\u30c9\u30c8\u30fc\u30af'};\n  const sorted = [...trends].sort((a,b) => b.cnt - a.cnt).slice(0, 15);\n  document.getElementById('trendsList').innerHTML = sorted.map((t, i) => `\n    <div class=\"tr-item\" onclick=\"useTrend('${t.tag}')\">\n      <div class=\"tr-rank${i < 3 ? ' top' : ''}\">${i+1}</div>\n      <div class=\"tr-info\"><div class=\"tr-tag\">${esc(t.tag)}</div><div class=\"tr-meta\">${ml[t.mode]||t.mode}</div></div>\n      <div class=\"tr-cnt\">${fmt(t.cnt)}\u4ef6</div>\n    </div>`).join('');\n}\nfunction useTrend(tag) {\n  showPanel('timeline');\n  const inp = document.getElementById('postInput');\n  if (inp) { inp.value = tag + ' '; inp.focus(); document.getElementById('sendBtn').disabled = false; }\n}\n\n// ===================================================\n//  \u30d7\u30ed\u30d5\u30a3\u30fc\u30eb\n// ===================================================\nfunction updProfile() {\n  document.getElementById('prAv').textContent   = user.avatar || '\ud83d\ude0a';\n  document.getElementById('prName').textContent = user.name   || '\u2014';\n  document.getElementById('prId').textContent   = user.id     || '@\u2014';\n  const all = Object.values(mPosts).flat();\n  document.getElementById('stP').textContent = all.filter(p => p.type === 'user').length;\n  document.getElementById('stL').textContent = fmt(all.reduce((s,p) => s + (p.liked?1:0), 0));\n  document.getElementById('stC').textContent = all.reduce((s,p) => s + (p.comments?.length||0), 0);\n  document.getElementById('prInts').innerHTML =\n    (user.interests||[]).map(i => `<div class=\"pr-tag\">${esc(i)}</div>`).join('') ||\n    '<span style=\"color:var(--sub);font-size:13px;\">\u672a\u8a2d\u5b9a</span>';\n}\nfunction updCmpAv() {\n  const el = document.getElementById('cmpAv');\n  if (el) el.textContent = user.avatar || '\ud83d\ude0a';\n}\nfunction editProfile() {\n  document.getElementById('sName').value = user.name;\n  document.getElementById('sId').value   = user.id.replace('@','');\n  document.querySelectorAll('.av-item').forEach(e => e.classList.toggle('sel', e.dataset.av === user.avatar));\n  document.querySelectorAll('.int-tag').forEach(e => e.classList.toggle('sel', user.interests.includes(e.textContent.trim())));\n  selAv_ = user.avatar;\n  document.getElementById('setupBtn').textContent = '\u66f4\u65b0\u3059\u308b \u2192';\n  document.getElementById('setupBtn').disabled = false;\n  document.getElementById('mainScreen').classList.remove('active');\n  document.getElementById('mainScreen').style.display = 'none';\n  document.getElementById('setupScreen').classList.add('active');\n}\nfunction clearAll() {\n  if (!confirm('\u3059\u3079\u3066\u306e\u30c7\u30fc\u30bf\u3092\u524a\u9664\u3057\u307e\u3059\u304b\uff1f')) return;\n  ltimers.forEach(t => clearTimeout(t)); ltimers = [];\n  localStorage.removeItem(STORE_KEY);\n  mPosts = {influencer:[],mental:[],debate:[],legend:[]};\n  trends = []; notifs = []; pidCtr = 0; unread = 0;\n  user = {name:'',id:'',avatar:'\ud83d\ude0a',interests:[],theme:user.theme};\n  document.getElementById('mainScreen').classList.remove('active');\n  document.getElementById('mainScreen').style.display = 'none';\n  document.getElementById('setupScreen').classList.add('active');\n  ['sName','sId'].forEach(id => document.getElementById(id).value = '');\n  document.getElementById('setupBtn').disabled = true;\n  document.getElementById('setupBtn').textContent = '\u3044\u3069\u3070\u305f\u3092\u306f\u3058\u3081\u308b \u2192';\n  document.querySelectorAll('.int-tag,.av-item').forEach(e => e.classList.remove('sel'));\n  document.querySelector('.av-item').classList.add('sel');\n  selAv_ = '\ud83d\ude0a';\n}\n\n// ===================================================\n//  \u30d5\u30a9\u30fc\u30eb\u30d0\u30c3\u30af\u8fd4\u4fe1\n// ===================================================\nfunction getFallback(mode) {\n  const s = {\n    influencer:[\n      {name:'\u8c61\u306e\u308a\u9020',id:'@zou',avatar:'\ud83d\udc18',comment:'\u3053\u308c\u306f\u30d0\u30ba\u308b\u3084\u3064\uff01\uff01\u5b8c\u5168\u306b\u540c\u610f\ud83d\udd25',likes:2341},\n      {name:'\u7b4b\u8089\u5bff\u559c\u7537',id:'@kinniku',avatar:'\ud83d\udcaa',comment:'\u3081\u3061\u3083\u304f\u3061\u3083\u308f\u304b\u308b\u301c\uff01\u6bce\u65e5\u3053\u308c\u601d\u3063\u3066\u305f\u7b11',likes:887},\n      {name:'\u30c1\u30ef\u30ef\u306b\u306a\u308a\u305f\u3044\u72ac',id:'@chiwawa',avatar:'\ud83d\udc15',comment:'\u5929\u624d\u304b\uff1f\uff1fSNS\u306b\u6d41\u3057\u3066\u307b\u3057\u3044',likes:321},\n    ],\n    mental:[\n      {name:'\u30d1\u30bd\u30b3\u30f3\u3081\u304c\u306d',id:'@megane',avatar:'\ud83d\udc53',comment:'\u305d\u308c\u3001\u3059\u3054\u304f\u8f9b\u304b\u3063\u305f\u306d\u3002\u8a71\u3057\u3066\u304f\u308c\u3066\u3042\u308a\u304c\u3068\u3046\u3002',likes:102},\n      {name:'\u3054\u98ef\u529b\u58eb',id:'@gohan',avatar:'\ud83c\udf5a',comment:'\u3042\u306a\u305f\u306e\u6c17\u6301\u3061\u3001\u3061\u3083\u3093\u3068\u53d7\u3051\u53d6\u3063\u305f\u3088\u3002\u7121\u7406\u3057\u306a\u3044\u3067\u3002',likes:580},\n    ],\n    debate:[\n      {name:'\u3089\u304f\u3060\u5c0f\u50e7',id:'@rakuda',avatar:'\ud83d\udc2a',comment:'\u4e00\u5ea6\u306f\u81ea\u5206\u3067\u8003\u3048\u308b\u3053\u3068\u3092\u304a\u3059\u3059\u3081\u3057\u307e\u3059\uff01\u7b54\u3048\u306f\u81ea\u5206\u306e\u4e2d\u306b\u3042\u308a\u307e\u3059\u3002',likes:1572},\n      {name:'\u5f37\u9762\u304a\u3058\u3055\u3093',id:'@kowamote',avatar:'\ud83d\ude24',comment:'\u666e\u901a\u306b\u3084\u3063\u3066\u3066\u3082\u610f\u5473\u306a\u3044\u3063\u3066\u601d\u3063\u305f\u3089AI\u306b\u4e38\u6295\u3052\u3067\u3082\u3088\u304f\u306d\u3002',likes:294},\n    ],\n    legend:[\n      {name:'\u30d6\u30c3\u30c0',id:'@buddha',avatar:'\ud83e\uddd8',comment:'\u300c\u3044\u3044\u306d\u300d\u304c\u6b32\u3057\u304f\u3066\u5fc3\u304c\u3056\u308f\u3064\u304f\u306a\u3089\u3001\u30b9\u30de\u30db\u3092\u7f6e\u3044\u3066\u76ee\u3092\u9589\u3058\u306a\u3055\u3044\u3002',likes:78000},\n      {name:'\u30bd\u30af\u30e9\u30c6\u30b9',id:'@socrates',avatar:'\ud83c\udfdb\ufe0f',comment:'\u6b63\u7fa9\u3068\u306f\u4f55\u3067\u3059\u304b\uff1f\u8ab0\u304b\u79c1\u306b\u6559\u3048\u3066\u304f\u308c\u307e\u305b\u3093\u304b\uff1f',likes:990},\n    ]\n  };\n  return s[mode] || s.influencer;\n}\n\n// ===================================================\n//  \u30e6\u30fc\u30c6\u30a3\u30ea\u30c6\u30a3\n// ===================================================\nfunction autoResize(el) { el.style.height = 'auto'; el.style.height = Math.min(el.scrollHeight, 100) + 'px'; }\nfunction handleKey(e) {\n  if (e.key === 'Enter' && !e.shiftKey) {\n    e.preventDefault();\n    const sb = document.getElementById('sendBtn');\n    if (!sb.disabled) submitPost();\n  }\n}\nfunction scrollBot() {\n  const p = document.getElementById('pTimeline');\n  if (p) setTimeout(() => { p.scrollTop = p.scrollHeight; }, 100);\n}\nfunction fmt(n) {\n  n = Number(n) || 0;\n  if (n >= 10000) return (n / 10000).toFixed(1) + '\u4e07';\n  return n.toLocaleString();\n}\nfunction esc(s) {\n  return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\\n/g,'<br>');\n}\nfunction toast(msg) {\n  const t = document.getElementById('toast');\n  t.textContent = msg; t.classList.add('show');\n  setTimeout(() => t.classList.remove('show'), 2600);\n}\nfunction showLd(txt = '') {\n  document.getElementById('overlay').classList.remove('hide');\n  if (txt) document.getElementById('ovTxt').textContent = txt;\n}\nfunction hideLd() { document.getElementById('overlay').classList.add('hide'); }\nfunction timeAgo(ts) {\n  const s = Math.floor((Date.now() - ts) / 1000);\n  if (s < 60) return s + '\u79d2\u524d';\n  if (s < 3600) return Math.floor(s/60) + '\u5206\u524d';\n  if (s < 86400) return Math.floor(s/3600) + '\u6642\u9593\u524d';\n  return Math.floor(s/86400) + '\u65e5\u524d';\n}\n\n// ===================================================\n//  \u4fdd\u5b58\u30fb\u8aad\u307f\u8fbc\u307f\n// ===================================================\nfunction saveData() {\n  try {\n    localStorage.setItem(STORE_KEY, JSON.stringify({user, mPosts, trends, notifs, pidCtr, curMode, unread}));\n  } catch(e) {}\n}\nfunction loadData() {\n  try {\n    const raw = localStorage.getItem(STORE_KEY); if (!raw) return false;\n    const d = JSON.parse(raw);\n    user   = d.user   || user;\n    mPosts = d.mPosts || {influencer:[],mental:[],debate:[],legend:[]};\n    trends = d.trends || []; notifs = d.notifs || [];\n    pidCtr = d.pidCtr || 0; curMode = d.curMode || 'influencer'; unread = d.unread || 0;\n    return true;\n  } catch(e) { return false; }\n}\n\n// ===================================================\n//  \u521d\u671f\u5316\n// ===================================================\n(function init() {\n  showLd('\u8d77\u52d5\u4e2d\u2026');\n  const ok = loadData();\n  if (ok && user.name && user.id) {\n    toMain(false).then(() => {\n      if (unread > 0) document.getElementById('ndot').classList.add('show');\n      if (Object.values(mPosts).flat().some(p => p.type === 'user')) startLikeSim();\n      applyTheme(user.theme || 'dark');\n      applyMode(curMode);\n    });\n  } else {\n    hideLd();\n    document.getElementById('setupScreen').classList.add('active');\n    applyTheme('dark');\n  }\n\n  // \u6295\u7a3f\u30dc\u30bf\u30f3\u6709\u52b9\u5316\n  const ta = document.getElementById('postInput');\n  if (ta) ta.addEventListener('input', () => {\n    document.getElementById('sendBtn').disabled = ta.value.trim() === '' || busy;\n  });\n\n  // \u30d0\u30c3\u30af\u30b0\u30e9\u30a6\u30f3\u30c9\u5fa9\u5e30\u6642\u306e\u3044\u3044\u306d\u51e6\u7406\n  let hidAt = null;\n  document.addEventListener('visibilitychange', () => {\n    if (document.hidden) {\n      hidAt = Date.now();\n    } else if (hidAt) {\n      const el = Date.now() - hidAt; hidAt = null;\n      if (el > 10000) {\n        const my = Object.values(mPosts).flat().filter(p => p.type === 'user');\n        const mins = Math.max(1, Math.floor(el / 60000));\n        my.forEach(p => autoLike(p.id, Math.floor(Math.random() * mins * 25) + mins));\n      }\n    }\n  });\n})();\n</script>\n</body>\n</html>";

// ===== ユーティリティ =====
function readBody(req) {
  return new Promise((resolve, reject) => {
    let b = '';
    req.on('data', c => { b += c; if (b.length > 200000) reject(new Error('too large')); });
    req.on('end', () => { try { resolve(JSON.parse(b || '{}')); } catch(e) { reject(e); } });
    req.on('error', reject);
  });
}

function sendJSON(res, status, data) {
  const body = JSON.stringify(data);
  res.writeHead(status, {
    'Content-Type': 'application/json',
    'Content-Length': Buffer.byteLength(body),
    ...(status === 429 ? {'Retry-After':'60'} : {})
  });
  res.end(body);
}

function httpsPost(hostname, path, headers, body) {
  return new Promise((resolve, reject) => {
    const s = JSON.stringify(body);
    const req = https.request(
      { hostname, path, method: 'POST',
        headers: {'Content-Type':'application/json','Content-Length':Buffer.byteLength(s),...headers} },
      res => {
        let raw = '';
        res.on('data', c => { raw += c; });
        res.on('end', () => {
          if (res.statusCode === 429) { reject(new Error('GEMINI_QUOTA_EXCEEDED')); return; }
          if (res.statusCode >= 400)  { reject(new Error(`HTTP ${res.statusCode}: ${raw.slice(0,300)}`)); return; }
          try { resolve(JSON.parse(raw)); } catch(e) { reject(new Error('JSON parse error: ' + raw.slice(0,200))); }
        });
      }
    );
    req.on('error', reject);
    req.write(s); req.end();
  });
}

// ===== AIレスポンスのパース（多段階フォールバック）=====
function parseAI(raw) {
  if (!raw || typeof raw !== 'string') throw new Error('空レスポンス');
  const c = raw.replace(/```json\s*/gi,'').replace(/```\s*/g,'').trim();

  try {
    const r = JSON.parse(c);
    // 新形式: { replies, timelinePosts }
    if (r && r.replies !== undefined && r.timelinePosts !== undefined) return r;
    // タイムライン形式: { posts }
    if (r && Array.isArray(r.posts)) return r;
    // 配列
    if (Array.isArray(r)) return r;
    if (r && typeof r === 'object') return r;
  } catch(_) {}

  // 配列抽出
  const am = c.match(/\[[\s\S]*?\]/);
  if (am) try { const r = JSON.parse(am[0]); if (Array.isArray(r) && r.length) return r; } catch(_) {}

  throw new Error('JSONパース失敗: ' + raw.slice(0, 200));
}

// ===== Gemini APIレート制御（4秒間隔）=====
let lastCall = 0;
async function waitRL_API() {
  const MIN = 4200;
  const el  = Date.now() - lastCall;
  if (el < MIN) await new Promise(r => setTimeout(r, MIN - el));
  lastCall = Date.now();
}

// ===== Gemini呼び出し =====
async function callGemini(prompt, schema) {
  await waitRL_API();
  const reqBody = {
    contents: [{ role: 'user', parts: [{ text: prompt }] }],
    generationConfig: {
      temperature: 0.88,
      maxOutputTokens: 2000,
      responseMimeType: 'application/json',
      responseSchema: schema   // ← スキーマ必須（ないと400エラー）
    }
  };
  console.log('[gemini] sending prompt (' + prompt.length + ' chars)');
  const d = await httpsPost(
    'generativelanguage.googleapis.com',
    `/v1beta/models/gemini-2.0-flash:generateContent?key=${GEMINI_KEY}`,
    {}, reqBody
  );
  const raw = d.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  console.log('[gemini] raw response: ' + raw.slice(0, 200));
  return parseAI(raw);
}

// ===== JSONスキーマ =====
// キャラクター共通アイテム
const CHAR_ITEM = {
  type: 'object',
  properties: {
    name:    { type: 'string' },
    id:      { type: 'string' },
    avatar:  { type: 'string' },
    comment: { type: 'string' },
    likes:   { type: 'integer' }
  },
  required: ['name', 'id', 'avatar', 'comment', 'likes']
};

// 投稿後: replies（コメント欄）+ timelinePosts（タイムライン）を1回で
const POST_SCHEMA = {
  type: 'object',
  properties: {
    replies:       { type: 'array', items: CHAR_ITEM },
    timelinePosts: { type: 'array', items: CHAR_ITEM }
  },
  required: ['replies', 'timelinePosts']
};

// 起動時タイムライン
const TL_SCHEMA = {
  type: 'object',
  properties: { posts: { type: 'array', items: CHAR_ITEM } },
  required: ['posts']
};

// ===== プロンプト構築 =====
function buildPostPrompt(postText, mode, interests) {
  const int = interests.length ? interests.join('、') : '未設定';
  const cfg = {
    influencer: {
      rChars: '熱狂的なSNSユーザー5〜7人',
      rRule:  '投稿の言葉・話題・感情に直接触れて絶賛・共感・拡散したがる反応。バズりそうな表現で。likes:300〜99999。',
      tDesc:  '投稿テーマに関連した他ユーザーたちの独り言・つぶやき（4〜6件）。ユーザーへの返信ではなく独自の感想や情報シェア。',
    },
    mental: {
      rChars: '共感力の高い優しいユーザー4〜6人',
      rRule:  '投稿の具体的な悩みや気持ちを受け止め温かく寄り添うリプライ。likes:10〜2000。',
      tDesc:  '投稿テーマに関連した、心の声や悩みをつぶやくユーザーたちの投稿（3〜5件）。共感しやすい内容。',
    },
    debate: {
      rChars: '賛成派・反対派・中立派が混在する5〜7人',
      rRule:  '投稿の主張・意見に対し異なる立場から具体的に議論するリプライ。likes:50〜8000。',
      tDesc:  '投稿テーマに関連した議論・意見のつぶやき（4〜6件）。様々な立場からの独自の考え方。',
    },
    legend: {
      rChars: '歴史上の実在した偉人4〜6人',
      rRule:  '投稿テーマに関連した名言・哲学を引用しつつ返信するリプライ。likes:1000〜100000。',
      tDesc:  '投稿テーマに関連した歴史上の偉人たちの独自つぶやき（3〜5件）。名言や哲学的考察。',
    },
  }[mode] || {rChars:'SNSユーザー5人',rRule:'コメント。',tDesc:'つぶやき（4件）。'};

  return `## 返信対象の投稿
「${postText}」

## 設定
モード: ${mode} / ユーザーの趣味: ${int}

## 生成タスク

### replies（この投稿へのリプライ ← コメント欄に表示される）
${cfg.rChars}が上の投稿に日本語でリプライしてください。
ルール: ${cfg.rRule}
各コメントは投稿の具体的なキーワード・内容・感情に必ず直接言及すること。汎用コメント禁止。

### timelinePosts（タイムラインに流れるAIキャラの独り言・つぶやき）
${cfg.tDesc}
ユーザーへの返信ではなく、投稿テーマに関連した独自のつぶやき。自然な日本語口語で。`;
}

function buildTLPrompt(interests, mode) {
  const int = interests.length ? interests.join('、') : '未設定';
  const ml  = {influencer:'インフルエンサー',mental:'メンタルケア',debate:'ディベート',legend:'レジェンドトーク'}[mode] || mode;
  return `## タスク
日本語SNS「いどばた」(モード: ${ml})の初期タイムライン投稿を7〜9件生成してください。

## 条件
- ユーザーの趣味: ${int}
- 趣味に直接関連した具体的な内容の投稿（汎用的な内容は不可）
- 個性的なSNSユーザーらしい自然な日本語口語
- likes: 100〜50000`;
}

// ===== HTTPサーバー =====
http.createServer(async (req, res) => {
  const path = req.url.split('?')[0];
  const ip   = req.headers['x-forwarded-for']?.split(',')[0].trim()
             || req.socket.remoteAddress || 'unknown';

  res.setHeader('Access-Control-Allow-Origin', '*');
  if (req.method === 'OPTIONS') {
    res.writeHead(204, {'Access-Control-Allow-Headers':'Content-Type'}); res.end(); return;
  }

  // ヘルスチェック
  if (path === '/api/health') {
    sendJSON(res, 200, {status:'ok', provider:'gemini', hasKey:!!GEMINI_KEY}); return;
  }

  // ===== POST /api/post =====
  // 投稿テキストを受け取り、replies + timelinePosts を1回のGemini呼び出しで返す
  if (req.method === 'POST' && path === '/api/post') {
    if (!checkRL(ip)) {
      console.warn('[rate-limit] ip:', ip);
      sendJSON(res, 429, {error:'リクエストが多すぎます。1分後に再試行してください。', replies:[], timelinePosts:[]});
      return;
    }
    try {
      const {text, mode='influencer', interests=[]} = await readBody(req);
      if (!text) { sendJSON(res, 400, {error:'text required', replies:[], timelinePosts:[]}); return; }
      const vm = ['influencer','mental','debate','legend'].includes(mode) ? mode : 'influencer';
      console.log(`[post] mode=${vm} text="${text.slice(0,50)}"`);

      const result = await callGemini(buildPostPrompt(text, vm, interests), POST_SCHEMA);
      sendJSON(res, 200, {
        replies:       result.replies       || [],
        timelinePosts: result.timelinePosts || []
      });
    } catch(e) {
      console.error('[post error]', e.message);
      if (e.message === 'GEMINI_QUOTA_EXCEEDED')
        sendJSON(res, 503, {error:'QUOTA_EXCEEDED', replies:[], timelinePosts:[]});
      else
        sendJSON(res, 500, {error: e.message, replies:[], timelinePosts:[]});
    }
    return;
  }

  // ===== POST /api/timeline =====
  // 起動時の初回タイムライン生成
  if (req.method === 'POST' && path === '/api/timeline') {
    if (!checkRL('tl_' + ip)) {
      sendJSON(res, 429, {error:'リクエストが多すぎます。', posts:[]}); return;
    }
    try {
      const {interests=[], mode='influencer'} = await readBody(req);
      console.log(`[timeline] mode=${mode} ip=${ip}`);
      const result = await callGemini(buildTLPrompt(interests, mode), TL_SCHEMA);
      sendJSON(res, 200, {posts: result.posts || []});
    } catch(e) {
      console.error('[timeline error]', e.message);
      sendJSON(res, e.message === 'GEMINI_QUOTA_EXCEEDED' ? 503 : 500, {error: e.message, posts:[]});
    }
    return;
  }

  // ===== index.html =====
  const html = Buffer.from(INDEX_HTML, 'utf8');
  res.writeHead(200, {'Content-Type':'text/html; charset=utf-8', 'Content-Length': html.length});
  res.end(html);

}).listen(PORT, () => {
  console.log(`✅ いどばたサーバー起動 ポート: ${PORT}`);
  console.log(`🤖 Gemini 2.0 Flash / キー: ${GEMINI_KEY ? '設定済み✅' : '未設定❌'}`);
  console.log(`🛡️  レート制限: ${RL_MAX}req/${RL_WIN/1000}s per IP`);
});
